DROP TABLE IF EXISTS `fixture_participant`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `fixture_participant` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `fixture_id` int(11) DEFAULT NULL COMMENT 'FK fixture',
  `team_id` int(11) DEFAULT NULL COMMENT 'FK team',
  `role` varchar(1) DEFAULT NULL COMMENT 'A or B (from source)',
  `score` int(11) DEFAULT NULL COMMENT 'Goals in regular time',
  `score_extra` int(11) DEFAULT NULL COMMENT 'Extra time goals (optional)',
  `score_penalty` int(11) DEFAULT NULL COMMENT 'Penalty shootout goals (optional)',
  `outcome` tinyint(1) DEFAULT NULL COMMENT 'Winner or not' CHECK (`outcome` in (0,1,2)),
  `venue_role` varchar(10) DEFAULT NULL COMMENT 'HOME/AWAY/NEUTRAL/UNKNOWN (derived)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_fixture_participant_fixture_id_role` (`fixture_id`,`role`),
  KEY `ix_fixture_participant_team_id` (`team_id`),
  KEY `ix_fixture_participant_fixture_id` (`fixture_id`),
  CONSTRAINT `fk_fixture_participant_fixture_id` FOREIGN KEY (`fixture_id`) REFERENCES `fixture` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_fixture_participant_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1355 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
