--
-- Table structure for table `person_assignment`
--

DROP TABLE IF EXISTS `person_assignment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `person_assignment` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `person_id` int(11) NOT NULL COMMENT 'FK person',
  `team_id` int(11) NOT NULL COMMENT 'FK team',
  `role_id` int(11) NOT NULL COMMENT 'FK role',
  `season_id` int(11) DEFAULT NULL COMMENT 'FK season',
  `from_date` date DEFAULT NULL COMMENT 'Début (NULL si inconnu)',
  `to_date` date DEFAULT NULL COMMENT 'Fin (NULL = en cours / inconnu)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_tpr_exact` (`person_id`,`team_id`,`role_id`,`season_id`,`from_date`,`to_date`),
  KEY `ix_tpr_role_dates` (`team_id`,`role_id`,`from_date`,`to_date`),
  KEY `ix_tpr_person_dates` (`person_id`,`from_date`,`to_date`),
  KEY `ix_tpr_season` (`season_id`),
  KEY `ix_pa_person_role_current` (`person_id`,`role_id`,`to_date`,`from_date`),
  KEY `ix_pa_person_from_to` (`person_id`,`from_date`,`to_date`),
  KEY `ix_pa_person_to_from` (`person_id`,`to_date`,`from_date`),
  KEY `ix_pa_team_from_to` (`team_id`,`from_date`,`to_date`),
  KEY `ix_pa_role_team_dates` (`role_id`,`team_id`,`from_date`,`to_date`),
  CONSTRAINT `fk_tpr_person_id` FOREIGN KEY (`person_id`) REFERENCES `person` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_tpr_role_id` FOREIGN KEY (`role_id`) REFERENCES `role` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `fk_tpr_season_id` FOREIGN KEY (`season_id`) REFERENCES `season` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_tpr_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=4878 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

