--
-- Table structure for table `scoresheet_lineup`
--

DROP TABLE IF EXISTS `scoresheet_lineup`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `scoresheet_lineup` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `scoresheet_id` int(11) DEFAULT NULL COMMENT 'FK scoresheet',
  `team_id` int(11) DEFAULT NULL COMMENT 'FK team',
  `player_id` int(11) DEFAULT NULL COMMENT 'FK player',
  `player_name_text` varchar(200) DEFAULT NULL COMMENT 'Fallback',
  `shirt_number` int(11) DEFAULT NULL COMMENT 'Shirt number',
  `lineup_role` varchar(12) DEFAULT NULL COMMENT 'STARTER/SUB',
  `is_captain` tinyint(1) DEFAULT NULL COMMENT 'Captain' CHECK (`is_captain` in (0,1)),
  `position_id` int(11) DEFAULT NULL COMMENT 'FK position',
  `sort_order` int(11) DEFAULT NULL COMMENT 'Order',
  PRIMARY KEY (`id`),
  KEY `ix_scoresheet_lineup_player_id` (`player_id`),
  KEY `ix_scoresheet_lineup_scoresheet_id` (`scoresheet_id`),
  KEY `fk_scoresheet_lineup_team_id` (`team_id`),
  KEY `fk_scoresheet_lineup_position_id` (`position_id`),
  CONSTRAINT `fk_scoresheet_lineup_player_id` FOREIGN KEY (`player_id`) REFERENCES `player` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_lineup_position_id` FOREIGN KEY (`position_id`) REFERENCES `position` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_lineup_scoresheet_id` FOREIGN KEY (`scoresheet_id`) REFERENCES `scoresheet` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_lineup_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=17454 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

