DROP TABLE IF EXISTS `scoresheet_official`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `scoresheet_official` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `scoresheet_id` int(11) DEFAULT NULL COMMENT 'FK scoresheet',
  `role` varchar(30) DEFAULT NULL COMMENT 'MAIN_REF/AR1/AR2/FOURTH/DELEGATE/DOCTOR',
  `person_id` int(11) DEFAULT NULL COMMENT 'FK person',
  `name_text` varchar(150) DEFAULT NULL COMMENT 'Fallback',
  PRIMARY KEY (`id`),
  KEY `fk_scoresheet_official_scoresheet_id` (`scoresheet_id`),
  KEY `fk_scoresheet_official_person_id` (`person_id`),
  CONSTRAINT `fk_scoresheet_official_person_id` FOREIGN KEY (`person_id`) REFERENCES `person` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_official_scoresheet_id` FOREIGN KEY (`scoresheet_id`) REFERENCES `scoresheet` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=682 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
