--
-- Table structure for table `scoresheet_staff`
--

DROP TABLE IF EXISTS `scoresheet_staff`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `scoresheet_staff` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `scoresheet_id` int(11) DEFAULT NULL COMMENT 'FK scoresheet',
  `team_id` int(11) DEFAULT NULL COMMENT 'FK team',
  `person_id` int(11) DEFAULT NULL COMMENT 'FK person',
  `role` varchar(32) NOT NULL COMMENT 'HEAD_COACH / ASSISTANT_COACH',
  PRIMARY KEY (`id`),
  KEY `fk_scoresheet_staff_scoresheet_id` (`scoresheet_id`),
  KEY `fk_scoresheet_staff_team_id` (`team_id`),
  KEY `fk_scoresheet_staff_person_id` (`person_id`),
  CONSTRAINT `fk_scoresheet_staff_person_id` FOREIGN KEY (`person_id`) REFERENCES `person` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_staff_scoresheet_id` FOREIGN KEY (`scoresheet_id`) REFERENCES `scoresheet` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_staff_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1341 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

