--
-- Table structure for table `scoresheet_substitution`
--

DROP TABLE IF EXISTS `scoresheet_substitution`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `scoresheet_substitution` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `scoresheet_id` int(11) DEFAULT NULL COMMENT 'FK scoresheet',
  `team_id` int(11) DEFAULT NULL COMMENT 'FK team',
  `player_out_id` int(11) DEFAULT NULL COMMENT 'FK player out',
  `player_in_id` int(11) DEFAULT NULL COMMENT 'FK player in',
  `player_out_text` varchar(200) DEFAULT NULL COMMENT 'Fallback',
  `player_in_text` varchar(200) DEFAULT NULL COMMENT 'Fallback',
  `minute` varchar(8) DEFAULT NULL COMMENT 'Minute e.g. 74, 90+2',
  PRIMARY KEY (`id`),
  KEY `fk_scoresheet_substitution_scoresheet_id` (`scoresheet_id`),
  KEY `fk_scoresheet_substitution_team_id` (`team_id`),
  KEY `fk_scoresheet_substitution_player_out_id` (`player_out_id`),
  KEY `fk_scoresheet_substitution_player_in_id` (`player_in_id`),
  CONSTRAINT `fk_scoresheet_substitution_player_in_id` FOREIGN KEY (`player_in_id`) REFERENCES `player` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_substitution_player_out_id` FOREIGN KEY (`player_out_id`) REFERENCES `player` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_substitution_scoresheet_id` FOREIGN KEY (`scoresheet_id`) REFERENCES `scoresheet` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_scoresheet_substitution_team_id` FOREIGN KEY (`team_id`) REFERENCES `team` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=3093 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

