CREATE TABLE `standing` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '#',
  `edition_id` int(11) DEFAULT NULL COMMENT 'FK edition',
  `stage_id` int(11) DEFAULT NULL COMMENT 'FK stage',
  `matchday_id` int(11) DEFAULT NULL COMMENT 'FK matchday (optional)',
  `team_id` int(11) DEFAULT NULL COMMENT 'FK team',
  `rank` int(11) DEFAULT NULL COMMENT 'Rank',
  `played` int(11) DEFAULT NULL COMMENT 'Played',
  `won` int(11) DEFAULT NULL COMMENT 'Won',
  `draw` int(11) DEFAULT NULL COMMENT 'Draw',
  `lost` int(11) DEFAULT NULL COMMENT 'Lost',
  `goals_for` int(11) DEFAULT NULL COMMENT 'GF',
  `goals_against` int(11) DEFAULT NULL COMMENT 'GA',
  `goal_diff` int(11) DEFAULT NULL COMMENT 'GD',
  `points` int(11) DEFAULT NULL COMMENT 'Points',
  `observation` varchar(200) DEFAULT NULL COMMENT 'Observation',
  `source_note` varchar(200) DEFAULT NULL COMMENT 'Source',
  PRIMARY KEY (`id`),
  KEY `ix_standing_team_id` (`team_id`),
  KEY `ix_standing_edition_id` (`edition_id`),
  KEY `fk_standing_stage_id` (`stage_id`),
  KEY `fk_standing_matchday_id` (`matchday_id`),
